import { Component, OnInit } from '@angular/core';
import { Schedule, ScheduleService } from '../../core/services/schedule.service';
import { NotificationService } from '../../core/services/notification.service';

@Component({
  selector: 'app-schedule',
  templateUrl: './schedule.component.html',
  styleUrls: ['./schedule.component.css']
})
export class ScheduleComponent implements OnInit {
  schedules: Schedule[] = [];
  filteredSchedules: Schedule[] = [];
  selectedClass = '';
  showForm = false;
  editingSchedule: Schedule | null = null;

  scheduleForm = {
    className: '',
    subject: '',
    dayOfWeek: '',
    startTime: '',
    endTime: ''
  };

  days = ['Lundi', 'Mardi', 'Mercredi', 'Jeudi', 'Vendredi', 'Samedi'];
  classes = ['6ème A', '6ème B', '5ème A', '5ème B', '4ème A', '4ème B', '3ème A', '3ème B'];

  constructor(
    private scheduleService: ScheduleService,
    private notification: NotificationService
  ) {}

  ngOnInit() { this.loadSchedules(); }

  loadSchedules() {
    this.scheduleService.getAll().subscribe({
      next: (data) => {
        this.schedules = data;
        this.filterSchedules();
      },
      error: () => this.notification.error('Erreur lors du chargement des emplois du temps')
    });
  }

  filterSchedules() {
    if (this.selectedClass) {
      this.filteredSchedules = this.schedules.filter(s => s.className === this.selectedClass);
    } else {
      this.filteredSchedules = this.schedules;
    }
  }

  openForm(schedule?: Schedule) {
    this.showForm = true;
    if (schedule) {
      this.editingSchedule = schedule;
      this.scheduleForm = { ...schedule };
    } else {
      this.editingSchedule = null;
      this.scheduleForm = { className: '', subject: '', dayOfWeek: '', startTime: '', endTime: '' };
    }
  }

  closeForm() {
    this.showForm = false;
    this.editingSchedule = null;
  }

  onSubmit() {
    if (this.editingSchedule) {
      this.scheduleService.update(this.editingSchedule.id!, this.scheduleForm).subscribe({
        next: () => {
          this.notification.success('Emploi du temps mis à jour');
          this.closeForm();
          this.loadSchedules();
        },
        error: () => this.notification.error('Erreur lors de la mise à jour')
      });
    } else {
      this.scheduleService.create(this.scheduleForm).subscribe({
        next: () => {
          this.notification.success('Emploi du temps créé');
          this.closeForm();
          this.loadSchedules();
        },
        error: () => this.notification.error('Erreur lors de la création')
      });
    }
  }

  deleteSchedule(id?: number) {
    if (!id || !confirm('Supprimer cet emploi du temps ?')) return;
    this.scheduleService.delete(id).subscribe({
      next: () => {
        this.notification.success('Emploi du temps supprimé');
        this.loadSchedules();
      },
      error: () => this.notification.error('Erreur lors de la suppression')
    });
  }

  getDayColor(day: string): string {
    const colors: any = {
      'Lundi': '#3b82f6',
      'Mardi': '#10b981',
      'Mercredi': '#f59e0b',
      'Jeudi': '#ef4444',
      'Vendredi': '#8b5cf6',
      'Samedi': '#ec4899'
    };
    return colors[day] || '#64748b';
  }
}
